    session['status'] = request.args.get('message').replace("*", "<strong>").replace("_","</strong><br />")   # This replaces asterisks (*) with bold text and underscores (_), markdown, to HTML formatting using Python's `str` replace method —>> 'request.args.get('message')'. Replace it according your requirements
